public class CoinChange {

    // Returns minimum number of coins to make amount, or -1 if impossible
    public static int minCoins(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1); // use amount+1 as 'infinity'
        dp[0] = 0;                   // base case: 0 coins for amount 0

        for (int i = 1; i <= amount; i++) {
            for (int coin : coins) {
                if (coin <= i) {
                    dp[i] = Math.min(dp[i], dp[i - coin] + 1);
                }
            }
        }

        return dp[amount] > amount ? -1 : dp[amount];
    }

    // Also return which coins were used (backtrack from dp table)
    public static List<Integer> coinsList(int[] coins, int amount) {
        int[] dp   = new int[amount + 1];
        int[] from = new int[amount + 1]; // track which coin was used
        Arrays.fill(dp, amount + 1);
        Arrays.fill(from, -1);
        dp[0] = 0;

        for (int i = 1; i <= amount; i++) {
            for (int coin : coins) {
                if (coin <= i && dp[i - coin] + 1 < dp[i]) {
                    dp[i]   = dp[i - coin] + 1;
                    from[i] = coin;
                }
            }
        }

        if (dp[amount] > amount) return Collections.emptyList();
        List<Integer> result = new ArrayList<>();
        for (int rem = amount; rem > 0; rem -= from[rem]) result.add(from[rem]);
        return result; // e.g. [25, 10, 5, 1] for amount=41
    }

    public static void main(String[] args) {
        System.out.println(minCoins(new int[]{1,5,10,25}, 41)); // 4 (25+10+5+1)
        System.out.println(minCoins(new int[]{1,3,4},    6));   // 2 (3+3)
        System.out.println(minCoins(new int[]{2},        3));   // -1 (impossible)
    }
}

public class LIS {

    // O(n log n) using patience sorting + binary search
    public static int lisLength(int[] nums) {
        int[] tails = new int[nums.length];
        int len = 0;

        for (int x : nums) {
            // Binary search: find leftmost index where tails[i] >= x
            int lo = 0, hi = len;
            while (lo < hi) {
                int mid = (lo + hi) / 2;
                if (tails[mid] < x) lo = mid + 1;
                else                hi = mid;
            }
            tails[lo] = x; // replace or extend
            if (lo == len) len++;
        }

        return len;
    }

    // O(n²) DP — easier to understand and reconstruct
    public static int lisDP(int[] nums) {
        int n = nums.length;
        int[] dp = new int[n];
        Arrays.fill(dp, 1); // every element is an IS of length 1

        int maxLen = 1;
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[j] < nums[i]) {
                    dp[i] = Math.max(dp[i], dp[j] + 1);
                }
            }
            maxLen = Math.max(maxLen, dp[i]);
        }
        return maxLen;
    }

    // Reconstruct the actual subsequence from O(n²) DP
    public static List<Integer> reconstruct(int[] nums) {
        int n = nums.length;
        int[] dp   = new int[n];
        int[] prev = new int[n];
        Arrays.fill(dp, 1);
        Arrays.fill(prev, -1);
        int maxLen = 1, maxIdx = 0;

        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[j] < nums[i] && dp[j] + 1 > dp[i]) {
                    dp[i]   = dp[j] + 1;
                    prev[i] = j;
                }
            }
            if (dp[i] > maxLen) { maxLen = dp[i]; maxIdx = i; }
        }

        LinkedList<Integer> result = new LinkedList<>();
        for (int i = maxIdx; i >= 0; i = prev[i]) {
            result.addFirst(nums[i]);
            if (prev[i] == -1) break;
        }
        return result;
    }

    public static void main(String[] args) {
        int[] arr = {10, 9, 2, 5, 3, 7, 101, 18};
        System.out.println(lisLength(arr)); // 4: [2,3,7,18] or [2,5,7,18]
    }
}

public class LCS {

    // Returns LCS length
    public static int lcsLength(String s1, String s2) {
        int m = s1.length(), n = s2.length();
        int[][] dp = new int[m + 1][n + 1];

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (s1.charAt(i - 1) == s2.charAt(j - 1)) {
                    dp[i][j] = dp[i-1][j-1] + 1;
                } else {
                    dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]);
                }
            }
        }
        return dp[m][n];
    }

    // Reconstruct the actual LCS string
    public static String lcsString(String s1, String s2) {
        int m = s1.length(), n = s2.length();
        int[][] dp = new int[m + 1][n + 1];
        for (int i = 1; i <= m; i++)
            for (int j = 1; j <= n; j++)
                if (s1.charAt(i-1) == s2.charAt(j-1)) dp[i][j] = dp[i-1][j-1] + 1;
                else dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]);

        // Backtrack
        StringBuilder sb = new StringBuilder();
        int i = m, j = n;
        while (i > 0 && j > 0) {
            if (s1.charAt(i-1) == s2.charAt(j-1)) {
                sb.append(s1.charAt(i-1));
                i--; j--;
            } else if (dp[i-1][j] > dp[i][j-1]) i--;
            else j--;
        }
        return sb.reverse().toString();
    }

    // Space-optimised: O(min(m,n)) using two rows
    public static int lcsSpaceOptimised(String s1, String s2) {
        if (s1.length() < s2.length()) { String t = s1; s1 = s2; s2 = t; } // s1 is longer
        int m = s1.length(), n = s2.length();
        int[] prev = new int[n + 1], curr = new int[n + 1];
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++)
                if (s1.charAt(i-1) == s2.charAt(j-1)) curr[j] = prev[j-1] + 1;
                else curr[j] = Math.max(prev[j], curr[j-1]);
            int[] tmp = prev; prev = curr; curr = tmp;
            Arrays.fill(curr, 0);
        }
        return prev[n];
    }

    public static void main(String[] args) {
        System.out.println(lcsLength("ABCBDAB", "BDCABA")); // 4
        System.out.println(lcsString("ABCBDAB", "BDCABA")); // "BCBA" or similar
    }
}

public class EditDistance {

    public static int minDistance(String s1, String s2) {
        int m = s1.length(), n = s2.length();
        int[][] dp = new int[m + 1][n + 1];

        // Base cases: transform empty string
        for (int i = 0; i <= m; i++) dp[i][0] = i; // delete all chars of s1
        for (int j = 0; j <= n; j++) dp[0][j] = j; // insert all chars of s2

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (s1.charAt(i-1) == s2.charAt(j-1)) {
                    dp[i][j] = dp[i-1][j-1]; // characters match — no operation
                } else {
                    dp[i][j] = 1 + Math.min(
                        dp[i-1][j-1],                  // replace
                        Math.min(dp[i-1][j], dp[i][j-1]) // delete, insert
                    );
                }
            }
        }
        return dp[m][n];
    }

    // Space-optimised O(min(m,n)) using two rows
    public static int minDistanceOptimised(String s1, String s2) {
        if (s1.length() < s2.length()) { String t = s1; s1 = s2; s2 = t; }
        int m = s1.length(), n = s2.length();
        int[] prev = new int[n + 1];
        for (int j = 0; j <= n; j++) prev[j] = j;

        for (int i = 1; i <= m; i++) {
            int[] curr = new int[n + 1];
            curr[0] = i;
            for (int j = 1; j <= n; j++) {
                if (s1.charAt(i-1) == s2.charAt(j-1)) curr[j] = prev[j-1];
                else curr[j] = 1 + Math.min(prev[j-1], Math.min(prev[j], curr[j-1]));
            }
            prev = curr;
        }
        return prev[n];
    }

    public static void main(String[] args) {
        System.out.println(minDistance("kitten",   "sitting"));  // 3
        System.out.println(minDistance("horse",    "ros"));      // 3
        System.out.println(minDistance("intention","execution"));// 5
    }
}

public class SubsetSum {

    // Returns true if some subset of arr sums to target
    public static boolean canAchieve(int[] arr, int target) {
        int n = arr.length;
        boolean[][] dp = new boolean[n + 1][target + 1];

        // Base case: sum 0 is always achievable (empty subset)
        for (int i = 0; i <= n; i++) dp[i][0] = true;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= target; j++) {
                dp[i][j] = dp[i-1][j]; // exclude current item
                if (arr[i-1] <= j) {
                    dp[i][j] |= dp[i-1][j - arr[i-1]]; // include current item
                }
            }
        }
        return dp[n][target];
    }

    // Space-optimised: O(target) using 1D array
    // IMPORTANT: iterate j from right to left to avoid using item twice
    public static boolean canAchieveOptimised(int[] arr, int target) {
        boolean[] dp = new boolean[target + 1];
        dp[0] = true;

        for (int item : arr) {
            // Right to left: prevents using same item twice
            for (int j = target; j >= item; j--) {
                dp[j] |= dp[j - item];
            }
        }
        return dp[target];
    }

    // Count number of subsets with exactly target sum
    public static int countSubsets(int[] arr, int target) {
        int[] dp = new int[target + 1];
        dp[0] = 1;
        for (int item : arr)
            for (int j = target; j >= item; j--)
                dp[j] += dp[j - item];
        return dp[target];
    }

    // Partition array into two equal-sum halves (reduce to subset sum)
    public static boolean canPartition(int[] arr) {
        int total = 0;
        for (int v : arr) total += v;
        if (total % 2 != 0) return false; // odd total — impossible
        return canAchieveOptimised(arr, total / 2);
    }

    public static void main(String[] args) {
        System.out.println(canAchieve(new int[]{3,34,4,12,5,2}, 9));  // true (4+5)
        System.out.println(canPartition(new int[]{1,5,11,5}));         // true (1+5+5=11)
    }
}
